// Infrastructure/Persistence/ApplicationDbContext.cs
public class ApplicationDbContext : DbContext, IApplicationDbContext
{
    private readonly IMediator _mediator;

    public ApplicationDbContext(DbContextOptions<ApplicationDbContext> options, IMediator mediator)
        : base(options) { _mediator = mediator; }

    public DbSet<User> Users => Set<User>();

    protected override void OnModelCreating(ModelBuilder mb)
    {
        mb.ApplyConfigurationsFromAssembly(Assembly.GetExecutingAssembly());
        base.OnModelCreating(mb);
    }

    public override async Task<int> SaveChangesAsync(CancellationToken ct = default)
    {
        var entities = ChangeTracker.Entries<BaseEntity>()
            .Where(e => e.Entity.DomainEvents.Any()).Select(e => e.Entity).ToList();
        var events = entities.SelectMany(e => e.DomainEvents).ToList();
        entities.ForEach(e => e.ClearDomainEvents());
        foreach (var ev in events)
            await _mediator.Publish(ev, ct);
        return await base.SaveChangesAsync(ct);
    }
}

// Infrastructure/Persistence/Configurations/UserConfiguration.cs
public class UserConfiguration : IEntityTypeConfiguration<User>
{
    public void Configure(EntityTypeBuilder<User> b)
    {
        b.ToTable("Users");
        b.Property(u => u.Name).HasMaxLength(100).IsRequired();
        b.OwnsOne(u => u.Email, e =>
        {
            e.Property(x => x.Value).HasColumnName("Email").HasMaxLength(256).IsRequired();
            e.HasIndex(x => x.Value).IsUnique();
        });
        b.Property(u => u.Role).HasConversion<string>().HasMaxLength(50);
    }
}

// Api/Controllers/UsersController.cs
[ApiController]
[Route("api/v1/[controller]")]
[Authorize]
public class UsersController : ControllerBase
{
    private readonly ISender _mediator;
    public UsersController(ISender mediator) => _mediator = mediator;

    [HttpPost]
    [ProducesResponseType(typeof(Guid), StatusCodes.Status201Created)]
    public async Task<IActionResult> CreateUser(
        [FromBody] CreateUserRequest request, CancellationToken ct = default)
    {
        var command = new CreateUserCommand(request.Name, request.Email, request.Password,
                                            User.GetOrganizationId());
        var id = await _mediator.Send(command, ct);
        return CreatedAtAction(nameof(GetUser), new { id }, id);
    }
}
